#!/usr/bin/env python3
"""Airtable CLI for listing, creating, updating, and retrieving records."""
import argparse
import json
import os
import sys
import requests


class AirtableClient:
    """Client for Airtable API interactions."""

    def __init__(self):
        self.api_key = os.environ.get("AIRTABLE_API_KEY", "")
        if not self.api_key:
            print(
                '{"error": "AIRTABLE_API_KEY environment variable required"}',
                file=sys.stderr,
            )
            sys.exit(1)
        self.base_id = os.environ.get("AIRTABLE_BASE_ID", "")
        if not self.base_id:
            print(
                '{"error": "AIRTABLE_BASE_ID environment variable required"}',
                file=sys.stderr,
            )
            sys.exit(1)
        self.base_url = f"https://api.airtable.com/v0/{self.base_id}"
        self.headers = {
            "Authorization": f"Bearer {self.api_key}",
            "Content-Type": "application/json",
        }

    def list_records(self, table):
        """List records from a table."""
        try:
            response = requests.get(
                f"{self.base_url}/{table}",
                headers=self.headers,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def get_record(self, table, record_id):
        """Get a single record by ID."""
        try:
            response = requests.get(
                f"{self.base_url}/{table}/{record_id}",
                headers=self.headers,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def create_record(self, table, fields):
        """Create a new record in a table."""
        payload = {"fields": fields}
        try:
            response = requests.post(
                f"{self.base_url}/{table}",
                headers=self.headers,
                json=payload,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def update_record(self, table, record_id, fields):
        """Update an existing record."""
        payload = {"fields": fields}
        try:
            response = requests.patch(
                f"{self.base_url}/{table}/{record_id}",
                headers=self.headers,
                json=payload,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }


def main():
    parser = argparse.ArgumentParser(description="Airtable CLI")
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")

    list_parser = subparsers.add_parser("list-records", help="List records from a table")
    list_parser.add_argument("--table", required=True, help="Table name")

    get_parser = subparsers.add_parser("get-record", help="Get a single record")
    get_parser.add_argument("--table", required=True, help="Table name")
    get_parser.add_argument("--record-id", required=True, help="Record ID")

    create_parser = subparsers.add_parser("create-record", help="Create a new record")
    create_parser.add_argument("--table", required=True, help="Table name")
    create_parser.add_argument(
        "--fields-json", required=True, help="JSON string of field values"
    )

    update_parser = subparsers.add_parser("update-record", help="Update a record")
    update_parser.add_argument("--table", required=True, help="Table name")
    update_parser.add_argument("--record-id", required=True, help="Record ID")
    update_parser.add_argument(
        "--fields-json", required=True, help="JSON string of field values"
    )

    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    client = AirtableClient()

    if args.command == "list-records":
        result = client.list_records(args.table)
    elif args.command == "get-record":
        result = client.get_record(args.table, args.record_id)
    elif args.command == "create-record":
        fields = json.loads(args.fields_json)
        result = client.create_record(args.table, fields)
    elif args.command == "update-record":
        fields = json.loads(args.fields_json)
        result = client.update_record(args.table, args.record_id, fields)

    print(json.dumps(result, indent=2))

    if "error" in result:
        sys.exit(1)
    sys.exit(0)


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""Algolia CLI for searching indices, listing indices, and managing objects."""
import argparse
import json
import os
import sys
import requests


class AlgoliaClient:
    """Client for Algolia API interactions."""

    def __init__(self):
        self.app_id = os.environ.get("ALGOLIA_APP_ID", "")
        if not self.app_id:
            print(
                '{"error": "ALGOLIA_APP_ID environment variable required"}',
                file=sys.stderr,
            )
            sys.exit(1)
        self.api_key = os.environ.get("ALGOLIA_API_KEY", "")
        if not self.api_key:
            print(
                '{"error": "ALGOLIA_API_KEY environment variable required"}',
                file=sys.stderr,
            )
            sys.exit(1)
        self.base_url = f"https://{self.app_id}-dsn.algolia.net/1/indexes"
        self.headers = {
            "X-Algolia-API-Key": self.api_key,
            "X-Algolia-Application-Id": self.app_id,
            "Content-Type": "application/json",
        }

    def search(self, index, query):
        """Search an index."""
        try:
            response = requests.post(
                f"{self.base_url}/{index}/query",
                headers=self.headers,
                json={"query": query},
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def list_indices(self):
        """List all indices."""
        try:
            response = requests.get(
                self.base_url,
                headers=self.headers,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def get_object(self, index, object_id):
        """Get an object by ID from an index."""
        try:
            response = requests.get(
                f"{self.base_url}/{index}/{object_id}",
                headers=self.headers,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def add_object(self, index, body):
        """Add an object to an index."""
        try:
            response = requests.post(
                f"{self.base_url}/{index}",
                headers=self.headers,
                json=body,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }


def main():
    parser = argparse.ArgumentParser(description="Algolia CLI")
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")

    search_parser = subparsers.add_parser("search", help="Search an index")
    search_parser.add_argument("--index", required=True, help="Index name")
    search_parser.add_argument("--query", required=True, help="Search query")

    subparsers.add_parser("list-indices", help="List all indices")

    get_parser = subparsers.add_parser("get-object", help="Get an object by ID")
    get_parser.add_argument("--index", required=True, help="Index name")
    get_parser.add_argument("--object-id", required=True, help="Object ID")

    add_parser = subparsers.add_parser("add-object", help="Add an object to an index")
    add_parser.add_argument("--index", required=True, help="Index name")
    add_parser.add_argument(
        "--body-json", required=True, help="JSON object to add"
    )

    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    client = AlgoliaClient()

    if args.command == "search":
        result = client.search(args.index, args.query)
    elif args.command == "list-indices":
        result = client.list_indices()
    elif args.command == "get-object":
        result = client.get_object(args.index, args.object_id)
    elif args.command == "add-object":
        body = json.loads(args.body_json)
        result = client.add_object(args.index, body)

    print(json.dumps(result, indent=2))

    if isinstance(result, dict) and "error" in result:
        sys.exit(1)
    sys.exit(0)


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""Anthropic CLI for chat completions and token counting via the official SDK."""
import argparse
import json
import os
import sys

try:
    import anthropic
except ImportError:
    print(
        '{"error": "anthropic package not installed. Run: pip install anthropic>=0.18.0"}',
        file=sys.stderr,
    )
    sys.exit(1)


class AnthropicClient:
    """Client for Anthropic API interactions via the official SDK."""

    def __init__(self):
        self.api_key = os.environ.get("ANTHROPIC_API_KEY", "")
        if not self.api_key:
            print(
                '{"error": "ANTHROPIC_API_KEY environment variable required"}',
                file=sys.stderr,
            )
            sys.exit(1)
        self.model = os.environ.get("ANTHROPIC_MODEL", "claude-sonnet-4-20250514")
        self.client = anthropic.Anthropic(api_key=self.api_key)

    def chat(self, message=None, messages_json=None):
        """Send a message to Claude."""
        if messages_json:
            try:
                messages = json.loads(messages_json)
            except json.JSONDecodeError as e:
                return {"error": f"Invalid messages JSON: {e}"}
        elif message:
            messages = [{"role": "user", "content": message}]
        else:
            return {"error": "Either --message or --messages-json is required"}

        try:
            response = self.client.messages.create(
                model=self.model,
                max_tokens=4096,
                messages=messages,
            )
            return {
                "id": response.id,
                "model": response.model,
                "role": response.role,
                "content": [
                    {"type": block.type, "text": block.text}
                    for block in response.content
                    if block.type == "text"
                ],
                "stop_reason": response.stop_reason,
                "usage": {
                    "input_tokens": response.usage.input_tokens,
                    "output_tokens": response.usage.output_tokens,
                },
            }
        except Exception as e:
            return {"error": str(e)}

    def count_tokens(self, text):
        """Count tokens for the given text using the Anthropic tokenizer."""
        try:
            response = self.client.messages.count_tokens(
                model=self.model,
                messages=[{"role": "user", "content": text}],
            )
            return {
                "input_tokens": response.input_tokens,
                "model": self.model,
            }
        except Exception as e:
            # Fallback: estimate using the messages API with a dry-run approach
            return {"error": str(e)}


def main():
    parser = argparse.ArgumentParser(description="Anthropic CLI")
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")

    chat_parser = subparsers.add_parser("chat", help="Send a chat message")
    chat_parser.add_argument("--message", help="Single user message")
    chat_parser.add_argument(
        "--messages-json",
        help='JSON array of messages (e.g., \'[{"role":"user","content":"Hello"}]\')',
    )

    count_parser = subparsers.add_parser("count-tokens", help="Count tokens in text")
    count_parser.add_argument("--text", required=True, help="Text to count tokens for")

    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    client = AnthropicClient()

    if args.command == "chat":
        result = client.chat(
            message=getattr(args, "message", None),
            messages_json=getattr(args, "messages_json", None),
        )
    elif args.command == "count-tokens":
        result = client.count_tokens(args.text)

    print(json.dumps(result, indent=2))

    if isinstance(result, dict) and "error" in result:
        sys.exit(1)
    sys.exit(0)


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""Asana CLI for managing workspaces, projects, and tasks."""
import argparse
import json
import os
import sys
import requests


class AsanaClient:
    """Client for Asana API interactions."""

    def __init__(self):
        self.token = os.environ.get("ASANA_ACCESS_TOKEN", "")
        if not self.token:
            print(
                '{"error": "ASANA_ACCESS_TOKEN environment variable required"}',
                file=sys.stderr,
            )
            sys.exit(1)
        self.base_url = "https://app.asana.com/api/1.0"
        self.headers = {
            "Authorization": f"Bearer {self.token}",
            "Accept": "application/json",
            "Content-Type": "application/json",
        }

    def list_workspaces(self):
        """List all accessible workspaces."""
        try:
            response = requests.get(
                f"{self.base_url}/workspaces",
                headers=self.headers,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def list_projects(self, workspace):
        """List projects in a workspace."""
        try:
            response = requests.get(
                f"{self.base_url}/projects",
                headers=self.headers,
                params={"workspace": workspace},
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def create_task(self, project, name, notes=""):
        """Create a new task in a project."""
        payload = {
            "data": {
                "name": name,
                "notes": notes,
                "projects": [project],
            }
        }

        try:
            response = requests.post(
                f"{self.base_url}/tasks",
                headers=self.headers,
                json=payload,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def get_task(self, task_id):
        """Get details of a specific task."""
        try:
            response = requests.get(
                f"{self.base_url}/tasks/{task_id}",
                headers=self.headers,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def update_task(self, task_id, completed=None):
        """Update a task's completion status."""
        payload = {"data": {}}
        if completed is not None:
            payload["data"]["completed"] = completed

        try:
            response = requests.put(
                f"{self.base_url}/tasks/{task_id}",
                headers=self.headers,
                json=payload,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }


def main():
    parser = argparse.ArgumentParser(description="Asana CLI")
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")

    subparsers.add_parser("list-workspaces", help="List workspaces")

    proj_parser = subparsers.add_parser("list-projects", help="List projects")
    proj_parser.add_argument("--workspace", required=True, help="Workspace GID")

    create_parser = subparsers.add_parser("create-task", help="Create a task")
    create_parser.add_argument("--project", required=True, help="Project GID")
    create_parser.add_argument("--name", required=True, help="Task name")
    create_parser.add_argument("--notes", default="", help="Task notes")

    get_parser = subparsers.add_parser("get-task", help="Get task details")
    get_parser.add_argument("--task-id", required=True, help="Task GID")

    update_parser = subparsers.add_parser("update-task", help="Update a task")
    update_parser.add_argument("--task-id", required=True, help="Task GID")
    update_parser.add_argument(
        "--completed",
        required=True,
        choices=["true", "false"],
        help="Mark task completed or not",
    )

    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    client = AsanaClient()

    if args.command == "list-workspaces":
        result = client.list_workspaces()
    elif args.command == "list-projects":
        result = client.list_projects(args.workspace)
    elif args.command == "create-task":
        result = client.create_task(args.project, args.name, args.notes)
    elif args.command == "get-task":
        result = client.get_task(args.task_id)
    elif args.command == "update-task":
        result = client.update_task(args.task_id, args.completed == "true")

    print(json.dumps(result, indent=2))

    if "error" in result:
        sys.exit(1)
    sys.exit(0)


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""Bitbucket CLI for managing repositories and pull requests."""
import argparse
import json
import os
import sys
import requests


class BitbucketClient:
    """Client for Bitbucket API interactions."""

    def __init__(self):
        self.username = os.environ.get("BITBUCKET_USERNAME", "")
        self.app_password = os.environ.get("BITBUCKET_APP_PASSWORD", "")
        if not self.username or not self.app_password:
            print(
                '{"error": "BITBUCKET_USERNAME and BITBUCKET_APP_PASSWORD environment variables required"}',
                file=sys.stderr,
            )
            sys.exit(1)
        self.default_workspace = os.environ.get("BITBUCKET_WORKSPACE", "")
        self.base_url = "https://api.bitbucket.org/2.0"
        self.auth = (self.username, self.app_password)

    def list_repos(self, workspace):
        """List repositories in a workspace."""
        try:
            response = requests.get(
                f"{self.base_url}/repositories/{workspace}",
                auth=self.auth,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def get_repo(self, workspace, repo_slug):
        """Get details of a specific repository."""
        try:
            response = requests.get(
                f"{self.base_url}/repositories/{workspace}/{repo_slug}",
                auth=self.auth,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def list_prs(self, workspace, repo_slug, state="OPEN"):
        """List pull requests for a repository."""
        try:
            response = requests.get(
                f"{self.base_url}/repositories/{workspace}/{repo_slug}/pullrequests",
                auth=self.auth,
                params={"state": state},
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def create_pr(self, workspace, repo_slug, title, source_branch, dest_branch="main"):
        """Create a pull request."""
        payload = {
            "title": title,
            "source": {"branch": {"name": source_branch}},
            "destination": {"branch": {"name": dest_branch}},
        }

        try:
            response = requests.post(
                f"{self.base_url}/repositories/{workspace}/{repo_slug}/pullrequests",
                auth=self.auth,
                json=payload,
                headers={"Content-Type": "application/json"},
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }


def main():
    parser = argparse.ArgumentParser(description="Bitbucket CLI")
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")

    repos_parser = subparsers.add_parser("list-repos", help="List repositories")
    repos_parser.add_argument("--workspace", required=True, help="Workspace slug")

    get_parser = subparsers.add_parser("get-repo", help="Get repository details")
    get_parser.add_argument("--workspace", required=True, help="Workspace slug")
    get_parser.add_argument("--repo-slug", required=True, help="Repository slug")

    prs_parser = subparsers.add_parser("list-prs", help="List pull requests")
    prs_parser.add_argument("--workspace", required=True, help="Workspace slug")
    prs_parser.add_argument("--repo-slug", required=True, help="Repository slug")
    prs_parser.add_argument(
        "--state", default="OPEN", help="PR state: OPEN, MERGED, DECLINED, SUPERSEDED"
    )

    create_parser = subparsers.add_parser("create-pr", help="Create a pull request")
    create_parser.add_argument("--workspace", required=True, help="Workspace slug")
    create_parser.add_argument("--repo-slug", required=True, help="Repository slug")
    create_parser.add_argument("--title", required=True, help="PR title")
    create_parser.add_argument(
        "--source-branch", required=True, help="Source branch name"
    )
    create_parser.add_argument(
        "--dest-branch", default="main", help="Destination branch (default: main)"
    )

    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    client = BitbucketClient()

    if args.command == "list-repos":
        result = client.list_repos(args.workspace)
    elif args.command == "get-repo":
        result = client.get_repo(args.workspace, args.repo_slug)
    elif args.command == "list-prs":
        result = client.list_prs(args.workspace, args.repo_slug, args.state)
    elif args.command == "create-pr":
        result = client.create_pr(
            args.workspace, args.repo_slug, args.title,
            args.source_branch, args.dest_branch,
        )

    print(json.dumps(result, indent=2))

    if "error" in result:
        sys.exit(1)
    sys.exit(0)


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""CircleCI CLI for managing pipelines, workflows, and jobs."""
import argparse
import json
import os
import sys
import requests


class CircleCIClient:
    """Client for CircleCI API interactions."""

    def __init__(self):
        self.token = os.environ.get("CIRCLECI_TOKEN", "")
        if not self.token:
            print(
                '{"error": "CIRCLECI_TOKEN environment variable required"}',
                file=sys.stderr,
            )
            sys.exit(1)
        self.base_url = "https://circleci.com/api/v2"
        self.headers = {
            "Circle-Token": self.token,
            "Accept": "application/json",
            "Content-Type": "application/json",
        }

    def list_pipelines(self, project_slug):
        """List pipelines for a project."""
        try:
            response = requests.get(
                f"{self.base_url}/project/{project_slug}/pipeline",
                headers=self.headers,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def get_pipeline(self, pipeline_id):
        """Get details of a specific pipeline."""
        try:
            response = requests.get(
                f"{self.base_url}/pipeline/{pipeline_id}",
                headers=self.headers,
                timeout=30,
            )
