#!/usr/bin/env python3
"""Cloudflare CLI for managing zones, DNS records, and Workers."""
import argparse
import json
import os
import sys
import requests


class CloudflareClient:
    """Client for Cloudflare v4 API interactions."""

    def __init__(self):
        self.token = os.environ.get("CLOUDFLARE_API_TOKEN", "")
        if not self.token:
            print(
                '{"error": "CLOUDFLARE_API_TOKEN environment variable required"}',
                file=sys.stderr,
            )
            sys.exit(1)
        self.base_url = "https://api.cloudflare.com/client/v4"
        self.headers = {
            "Authorization": f"Bearer {self.token}",
            "Content-Type": "application/json",
        }

    def list_zones(self):
        """List all zones (domains)."""
        try:
            response = requests.get(
                f"{self.base_url}/zones",
                headers=self.headers,
                params={"per_page": 50},
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def list_dns_records(self, zone_id):
        """List DNS records for a zone."""
        try:
            response = requests.get(
                f"{self.base_url}/zones/{zone_id}/dns_records",
                headers=self.headers,
                params={"per_page": 100},
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def create_dns_record(self, zone_id, record_type, name, content):
        """Create a DNS record in a zone."""
        payload = {
            "type": record_type,
            "name": name,
            "content": content,
            "ttl": 1,  # Auto TTL
        }

        try:
            response = requests.post(
                f"{self.base_url}/zones/{zone_id}/dns_records",
                headers=self.headers,
                json=payload,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def list_workers(self):
        """List all Workers scripts."""
        # First get the account ID
        try:
            accounts_resp = requests.get(
                f"{self.base_url}/accounts",
                headers=self.headers,
                params={"per_page": 1},
                timeout=30,
            )
            accounts_resp.raise_for_status()
            accounts_data = accounts_resp.json()
            accounts = accounts_data.get("result", [])
            if not accounts:
                return {"error": "No accounts found for this token"}

            account_id = accounts[0]["id"]

            response = requests.get(
                f"{self.base_url}/accounts/{account_id}/workers/scripts",
                headers=self.headers,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }


def main():
    parser = argparse.ArgumentParser(description="Cloudflare CLI")
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")

    subparsers.add_parser("list-zones", help="List all zones")

    dns_list_parser = subparsers.add_parser(
        "list-dns-records", help="List DNS records for a zone"
    )
    dns_list_parser.add_argument("--zone-id", required=True, help="Zone ID")

    dns_create_parser = subparsers.add_parser(
        "create-dns-record", help="Create a DNS record"
    )
    dns_create_parser.add_argument("--zone-id", required=True, help="Zone ID")
    dns_create_parser.add_argument(
        "--type", required=True, help="Record type (A, AAAA, CNAME, TXT, etc.)"
    )
    dns_create_parser.add_argument("--name", required=True, help="Record name")
    dns_create_parser.add_argument("--content", required=True, help="Record content")

    subparsers.add_parser("list-workers", help="List Workers scripts")

    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    client = CloudflareClient()

    if args.command == "list-zones":
        result = client.list_zones()
    elif args.command == "list-dns-records":
        result = client.list_dns_records(args.zone_id)
    elif args.command == "create-dns-record":
        result = client.create_dns_record(
            args.zone_id, args.type, args.name, args.content
        )
    elif args.command == "list-workers":
        result = client.list_workers()

    print(json.dumps(result, indent=2))

    if isinstance(result, dict) and "error" in result:
        sys.exit(1)
    sys.exit(0)


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""Confluence CLI for searching, creating, and updating pages and spaces."""
import argparse
import base64
import json
import os
import sys
import requests


class ConfluenceClient:
    """Client for Confluence API interactions."""

    def __init__(self):
        self.base_url = os.environ.get("CONFLUENCE_BASE_URL", "").rstrip("/")
        self.email = os.environ.get("CONFLUENCE_EMAIL", "")
        self.api_token = os.environ.get("CONFLUENCE_API_TOKEN", "")
        if not self.base_url or not self.email or not self.api_token:
            print(
                '{"error": "CONFLUENCE_BASE_URL, CONFLUENCE_EMAIL, and CONFLUENCE_API_TOKEN environment variables required"}',
                file=sys.stderr,
            )
            sys.exit(1)
        self.base_url = f"{self.base_url}/wiki/rest/api"
        auth_str = f"{self.email}:{self.api_token}"
        auth_bytes = base64.b64encode(auth_str.encode()).decode()
        self.headers = {
            "Authorization": f"Basic {auth_bytes}",
            "Accept": "application/json",
            "Content-Type": "application/json",
        }

    def search(self, cql):
        """Search Confluence using CQL."""
        try:
            response = requests.get(
                f"{self.base_url}/content/search",
                headers=self.headers,
                params={"cql": cql},
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def get_page(self, page_id):
        """Get a specific page by ID."""
        try:
            response = requests.get(
                f"{self.base_url}/content/{page_id}",
                headers=self.headers,
                params={"expand": "body.storage,version"},
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def create_page(self, space_key, title, body):
        """Create a new page in a space."""
        payload = {
            "type": "page",
            "title": title,
            "space": {"key": space_key},
            "body": {
                "storage": {
                    "value": body,
                    "representation": "storage",
                }
            },
        }

        try:
            response = requests.post(
                f"{self.base_url}/content",
                headers=self.headers,
                json=payload,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def update_page(self, page_id, title, body, version):
        """Update an existing page."""
        payload = {
            "type": "page",
            "title": title,
            "body": {
                "storage": {
                    "value": body,
                    "representation": "storage",
                }
            },
            "version": {"number": int(version)},
        }

        try:
            response = requests.put(
                f"{self.base_url}/content/{page_id}",
                headers=self.headers,
                json=payload,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def list_spaces(self):
        """List all accessible spaces."""
        try:
            response = requests.get(
                f"{self.base_url}/space",
                headers=self.headers,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }


def main():
    parser = argparse.ArgumentParser(description="Confluence CLI")
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")

    search_parser = subparsers.add_parser("search", help="Search with CQL")
    search_parser.add_argument("--cql", required=True, help="CQL query string")

    get_parser = subparsers.add_parser("get-page", help="Get page by ID")
    get_parser.add_argument("--page-id", required=True, help="Page ID")

    create_parser = subparsers.add_parser("create-page", help="Create a page")
    create_parser.add_argument("--space-key", required=True, help="Space key")
    create_parser.add_argument("--title", required=True, help="Page title")
    create_parser.add_argument(
        "--body", required=True, help="Page body (Confluence storage format)"
    )

    update_parser = subparsers.add_parser("update-page", help="Update a page")
    update_parser.add_argument("--page-id", required=True, help="Page ID")
    update_parser.add_argument("--title", required=True, help="Page title")
    update_parser.add_argument(
        "--body", required=True, help="Page body (Confluence storage format)"
    )
    update_parser.add_argument(
        "--version", required=True, help="New version number (increment current by 1)"
    )

    subparsers.add_parser("list-spaces", help="List spaces")

    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    client = ConfluenceClient()

    if args.command == "search":
        result = client.search(args.cql)
    elif args.command == "get-page":
        result = client.get_page(args.page_id)
    elif args.command == "create-page":
        result = client.create_page(args.space_key, args.title, args.body)
    elif args.command == "update-page":
        result = client.update_page(args.page_id, args.title, args.body, args.version)
    elif args.command == "list-spaces":
        result = client.list_spaces()

    print(json.dumps(result, indent=2))

    if "error" in result:
        sys.exit(1)
    sys.exit(0)


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""Datadog CLI for querying metrics, listing monitors, and searching logs."""
import argparse
import json
import os
import sys
import time
import requests


class DatadogClient:
    """Client for Datadog API interactions."""

    def __init__(self):
        self.api_key = os.environ.get("DATADOG_API_KEY", "")
        if not self.api_key:
            print(
                '{"error": "DATADOG_API_KEY environment variable required"}',
                file=sys.stderr,
            )
            sys.exit(1)
        self.app_key = os.environ.get("DATADOG_APP_KEY", "")
        if not self.app_key:
            print(
                '{"error": "DATADOG_APP_KEY environment variable required"}',
                file=sys.stderr,
            )
            sys.exit(1)
        site = os.environ.get("DATADOG_SITE", "datadoghq.com")
        self.base_url_v1 = f"https://api.{site}/api/v1"
        self.base_url_v2 = f"https://api.{site}/api/v2"
        self.headers = {
            "DD-API-KEY": self.api_key,
            "DD-APPLICATION-KEY": self.app_key,
            "Content-Type": "application/json",
        }

    def query_metrics(self, query, from_ts, to_ts):
        """Query time series metrics."""
        try:
            response = requests.get(
                f"{self.base_url_v1}/query",
                headers=self.headers,
                params={
                    "query": query,
                    "from": from_ts,
                    "to": to_ts,
                },
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def list_monitors(self):
        """List all monitors."""
        try:
            response = requests.get(
                f"{self.base_url_v1}/monitor",
                headers=self.headers,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def search_logs(self, query, from_ts, to_ts):
        """Search logs using the Datadog v2 logs API."""
        payload = {
            "filter": {
                "query": query,
                "from": from_ts,
                "to": to_ts,
            },
            "sort": "-timestamp",
            "page": {"limit": 50},
        }

        try:
            response = requests.post(
                f"{self.base_url_v2}/logs/events/search",
                headers=self.headers,
                json=payload,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }


def main():
    parser = argparse.ArgumentParser(description="Datadog CLI")
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")

    metrics_parser = subparsers.add_parser("query-metrics", help="Query time series metrics")
    metrics_parser.add_argument(
        "--query", required=True, help="Datadog metrics query (e.g., 'avg:system.cpu.user{*}')"
    )
    metrics_parser.add_argument(
        "--from", dest="from_ts", required=True,
        help="Start time as UNIX timestamp",
    )
    metrics_parser.add_argument(
        "--to", dest="to_ts", required=True,
        help="End time as UNIX timestamp",
    )

    subparsers.add_parser("list-monitors", help="List all monitors")

    logs_parser = subparsers.add_parser("search-logs", help="Search logs")
    logs_parser.add_argument("--query", required=True, help="Log search query")
    logs_parser.add_argument(
        "--from", dest="from_ts", required=True,
        help="Start time as ISO 8601 string (e.g., 2024-01-01T00:00:00Z)",
    )
    logs_parser.add_argument(
        "--to", dest="to_ts", required=True,
        help="End time as ISO 8601 string",
    )

    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    client = DatadogClient()

    if args.command == "query-metrics":
        result = client.query_metrics(args.query, args.from_ts, args.to_ts)
    elif args.command == "list-monitors":
        result = client.list_monitors()
    elif args.command == "search-logs":
        result = client.search_logs(args.query, args.from_ts, args.to_ts)

    print(json.dumps(result, indent=2))

    if isinstance(result, dict) and "error" in result:
        sys.exit(1)
    sys.exit(0)


