#!/usr/bin/env python3
"""Google Gemini CLI for chatting with Gemini models and listing available models."""
import argparse
import json
import os
import sys

import google.generativeai as genai


class GeminiClient:
    """Client for Google Gemini API interactions."""

    def __init__(self):
        self.api_key = os.environ.get("GEMINI_API_KEY", "")
        if not self.api_key:
            print(
                '{"error": "GEMINI_API_KEY environment variable required"}',
                file=sys.stderr,
            )
            sys.exit(1)
        genai.configure(api_key=self.api_key)
        self.model_name = os.environ.get("GEMINI_MODEL", "gemini-2.0-flash")

    def chat(self, message):
        """Send a message to a Gemini model."""
        try:
            model = genai.GenerativeModel(self.model_name)
            response = model.generate_content(message)
            return {
                "model": self.model_name,
                "text": response.text,
                "candidates": [
                    {
                        "content": {
                            "parts": [{"text": part.text} for part in c.content.parts],
                            "role": c.content.role,
                        },
                        "finish_reason": str(c.finish_reason),
                    }
                    for c in response.candidates
                ],
                "usage_metadata": {
                    "prompt_token_count": getattr(
                        response.usage_metadata, "prompt_token_count", None
                    ),
                    "candidates_token_count": getattr(
                        response.usage_metadata, "candidates_token_count", None
                    ),
                    "total_token_count": getattr(
                        response.usage_metadata, "total_token_count", None
                    ),
                },
            }
        except Exception as e:
            return {"error": str(e)}

    def list_models(self):
        """List available Gemini models."""
        try:
            models = genai.list_models()
            return {
                "models": [
                    {
                        "name": m.name,
                        "display_name": m.display_name,
                        "description": m.description,
                        "supported_generation_methods": m.supported_generation_methods,
                    }
                    for m in models
                ]
            }
        except Exception as e:
            return {"error": str(e)}


def main():
    parser = argparse.ArgumentParser(description="Google Gemini CLI")
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")

    chat_parser = subparsers.add_parser("chat", help="Send a message to Gemini")
    chat_parser.add_argument("--message", required=True, help="Message to send")

    subparsers.add_parser("list-models", help="List available models")

    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    client = GeminiClient()

    if args.command == "chat":
        result = client.chat(args.message)
    elif args.command == "list-models":
        result = client.list_models()

    print(json.dumps(result, indent=2))

    if "error" in result:
        sys.exit(1)
    sys.exit(0)


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""Grafana CLI for managing dashboards, alerts, and datasource queries."""
import argparse
import json
import os
import sys
import requests


class GrafanaClient:
    """Client for Grafana API interactions."""

    def __init__(self):
        self.grafana_url = os.environ.get("GRAFANA_URL", "").rstrip("/")
        self.api_key = os.environ.get("GRAFANA_API_KEY", "")
        if not self.grafana_url or not self.api_key:
            print(
                '{"error": "GRAFANA_URL and GRAFANA_API_KEY environment variables required"}',
                file=sys.stderr,
            )
            sys.exit(1)
        self.base_url = f"{self.grafana_url}/api"
        self.headers = {
            "Authorization": f"Bearer {self.api_key}",
            "Accept": "application/json",
            "Content-Type": "application/json",
        }

    def list_dashboards(self):
        """List all dashboards."""
        try:
            response = requests.get(
                f"{self.base_url}/search",
                headers=self.headers,
                params={"type": "dash-db"},
                timeout=30,
            )
            response.raise_for_status()
            return {"dashboards": response.json()}
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def get_dashboard(self, uid):
        """Get a dashboard by UID."""
        try:
            response = requests.get(
                f"{self.base_url}/dashboards/uid/{uid}",
                headers=self.headers,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def list_alerts(self):
        """List all alert rules."""
        try:
            response = requests.get(
                f"{self.base_url}/alertmanager/grafana/api/v2/alerts",
                headers=self.headers,
                timeout=30,
            )
            response.raise_for_status()
            return {"alerts": response.json()}
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def query_datasource(self, datasource_id, query_json):
        """Query a datasource with a raw query."""
        try:
            query_data = json.loads(query_json)
        except json.JSONDecodeError as e:
            return {"error": f"Invalid JSON in --query-json: {str(e)}"}

        payload = {
            "queries": [
                {
                    "datasourceId": int(datasource_id),
                    **query_data,
                }
            ],
            "from": "now-1h",
            "to": "now",
        }

        try:
            response = requests.post(
                f"{self.base_url}/ds/query",
                headers=self.headers,
                json=payload,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }


def main():
    parser = argparse.ArgumentParser(description="Grafana CLI")
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")

    subparsers.add_parser("list-dashboards", help="List dashboards")

    get_parser = subparsers.add_parser("get-dashboard", help="Get dashboard by UID")
    get_parser.add_argument("--uid", required=True, help="Dashboard UID")

    subparsers.add_parser("list-alerts", help="List alert rules")

    query_parser = subparsers.add_parser(
        "query-datasource", help="Query a datasource"
    )
    query_parser.add_argument(
        "--datasource-id", required=True, help="Datasource ID"
    )
    query_parser.add_argument(
        "--query-json", required=True, help="Query payload as JSON string"
    )

    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    client = GrafanaClient()

    if args.command == "list-dashboards":
        result = client.list_dashboards()
    elif args.command == "get-dashboard":
        result = client.get_dashboard(args.uid)
    elif args.command == "list-alerts":
        result = client.list_alerts()
    elif args.command == "query-datasource":
        result = client.query_datasource(args.datasource_id, args.query_json)

    print(json.dumps(result, indent=2))

    if "error" in result:
        sys.exit(1)
    sys.exit(0)


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""Groq CLI for chatting with Groq-hosted LLMs and listing models."""
import argparse
import json
import os
import sys

from groq import Groq


class GroqClient:
    """Client for Groq API interactions."""

    def __init__(self):
        self.api_key = os.environ.get("GROQ_API_KEY", "")
        if not self.api_key:
            print(
                '{"error": "GROQ_API_KEY environment variable required"}',
                file=sys.stderr,
            )
            sys.exit(1)
        self.model = os.environ.get("GROQ_MODEL", "llama-3.3-70b-versatile")
        self.client = Groq(api_key=self.api_key)

    def chat(self, message=None, messages_json=None):
        """Send a chat completion request."""
        try:
            if messages_json:
                messages = json.loads(messages_json)
            elif message:
                messages = [{"role": "user", "content": message}]
            else:
                return {"error": "Either --message or --messages-json is required"}

            response = self.client.chat.completions.create(
                model=self.model,
                messages=messages,
            )
            return {
                "id": response.id,
                "model": response.model,
                "choices": [
                    {
                        "index": c.index,
                        "message": {
                            "role": c.message.role,
                            "content": c.message.content,
                        },
                        "finish_reason": c.finish_reason,
                    }
                    for c in response.choices
                ],
                "usage": {
                    "prompt_tokens": response.usage.prompt_tokens,
                    "completion_tokens": response.usage.completion_tokens,
                    "total_tokens": response.usage.total_tokens,
                },
            }
        except Exception as e:
            return {"error": str(e)}

    def list_models(self):
        """List available models."""
        try:
            response = self.client.models.list()
            return {
                "models": [
                    {
                        "id": m.id,
                        "owned_by": m.owned_by,
                        "created": m.created,
                    }
                    for m in response.data
                ]
            }
        except Exception as e:
            return {"error": str(e)}


def main():
    parser = argparse.ArgumentParser(description="Groq CLI")
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")

    chat_parser = subparsers.add_parser("chat", help="Send a chat completion request")
    chat_parser.add_argument("--message", help="Single message to send")
    chat_parser.add_argument(
        "--messages-json",
        help='JSON array of messages (e.g., \'[{"role":"user","content":"Hi"}]\')',
    )

    subparsers.add_parser("list-models", help="List available models")

    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    client = GroqClient()

    if args.command == "chat":
        result = client.chat(
            message=getattr(args, "message", None),
            messages_json=getattr(args, "messages_json", None),
        )
    elif args.command == "list-models":
        result = client.list_models()

    print(json.dumps(result, indent=2))

    if "error" in result:
        sys.exit(1)
    sys.exit(0)


if __name__ == "__main__":
    main()

