#!/usr/bin/env python3
"""MongoDB CLI for querying and managing databases and collections."""
import argparse
import json
import os
import sys

try:
    from pymongo import MongoClient
    from pymongo.errors import PyMongoError
except ImportError:
    print(
        '{"error": "pymongo package required. Install with: pip install pymongo>=4.5.0"}',
        file=sys.stderr,
    )
    sys.exit(1)

from bson import json_util


class MongoDBClient:
    """Client for MongoDB interactions."""

    def __init__(self):
        self.uri = os.environ.get("MONGODB_URI", "")
        if not self.uri:
            print(
                '{"error": "MONGODB_URI environment variable required"}',
                file=sys.stderr,
            )
            sys.exit(1)
        try:
            self.client = MongoClient(self.uri, serverSelectionTimeoutMS=30000)
        except PyMongoError as e:
            print(
                json.dumps({"error": f"Failed to connect to MongoDB: {str(e)}"}),
                file=sys.stderr,
            )
            sys.exit(1)

    def list_databases(self):
        """List all databases."""
        try:
            databases = self.client.list_database_names()
            db_info = []
            for db_name in databases:
                stats = self.client[db_name].command("dbStats")
                db_info.append({
                    "name": db_name,
                    "size_bytes": stats.get("dataSize", 0),
                    "collections": stats.get("collections", 0),
                })
            return {"databases": db_info}
        except PyMongoError as e:
            return {"error": str(e)}

    def list_collections(self, database):
        """List collections in a database."""
        try:
            db = self.client[database]
            collections = db.list_collection_names()
            return {"database": database, "collections": collections}
        except PyMongoError as e:
            return {"error": str(e)}

    def find(self, database, collection, filter_json=None, limit=20):
        """Find documents in a collection."""
        try:
            db = self.client[database]
            coll = db[collection]
            query_filter = {}
            if filter_json:
                query_filter = json.loads(filter_json)
            cursor = coll.find(query_filter).limit(limit)
            documents = json.loads(json_util.dumps(list(cursor)))
            return {
                "database": database,
                "collection": collection,
                "documents": documents,
                "count": len(documents),
            }
        except json.JSONDecodeError as e:
            return {"error": f"Invalid JSON in --filter-json: {str(e)}"}
        except PyMongoError as e:
            return {"error": str(e)}

    def count(self, database, collection, filter_json=None):
        """Count documents in a collection."""
        try:
            db = self.client[database]
            coll = db[collection]
            query_filter = {}
            if filter_json:
                query_filter = json.loads(filter_json)
            doc_count = coll.count_documents(query_filter)
            return {
                "database": database,
                "collection": collection,
                "count": doc_count,
            }
        except json.JSONDecodeError as e:
            return {"error": f"Invalid JSON in --filter-json: {str(e)}"}
        except PyMongoError as e:
            return {"error": str(e)}


def main():
    parser = argparse.ArgumentParser(description="MongoDB CLI")
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")

    subparsers.add_parser("list-databases", help="List databases")

    coll_parser = subparsers.add_parser(
        "list-collections", help="List collections in a database"
    )
    coll_parser.add_argument("--database", required=True, help="Database name")

    find_parser = subparsers.add_parser("find", help="Find documents")
    find_parser.add_argument("--database", required=True, help="Database name")
    find_parser.add_argument("--collection", required=True, help="Collection name")
    find_parser.add_argument(
        "--filter-json", help="Filter query as JSON string"
    )
    find_parser.add_argument(
        "--limit", type=int, default=20, help="Max documents (default: 20)"
    )

    count_parser = subparsers.add_parser("count", help="Count documents")
    count_parser.add_argument("--database", required=True, help="Database name")
    count_parser.add_argument("--collection", required=True, help="Collection name")
    count_parser.add_argument(
        "--filter-json", help="Filter query as JSON string"
    )

    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    client = MongoDBClient()

    if args.command == "list-databases":
        result = client.list_databases()
    elif args.command == "list-collections":
        result = client.list_collections(args.database)
    elif args.command == "find":
        result = client.find(
            args.database, args.collection, args.filter_json, args.limit
        )
    elif args.command == "count":
        result = client.count(args.database, args.collection, args.filter_json)

    print(json.dumps(result, indent=2, default=str))

    if "error" in result:
        sys.exit(1)
    sys.exit(0)


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""MySQL CLI for querying and managing MySQL databases."""
import argparse
import json
import os
import sys

try:
    import mysql.connector
    from mysql.connector import Error as MySQLError
except ImportError:
    print(
        '{"error": "mysql-connector-python package required. Install with: pip install mysql-connector-python>=8.1.0"}',
        file=sys.stderr,
    )
    sys.exit(1)


class MySQLClient:
    """Client for MySQL interactions."""

    def __init__(self):
        self.host = os.environ.get("MYSQL_HOST", "")
        self.user = os.environ.get("MYSQL_USER", "")
        self.password = os.environ.get("MYSQL_PASSWORD", "")
        self.database = os.environ.get("MYSQL_DATABASE", "")
        self.port = int(os.environ.get("MYSQL_PORT", "3306"))
        if not self.host or not self.user or not self.password or not self.database:
            print(
                '{"error": "MYSQL_HOST, MYSQL_USER, MYSQL_PASSWORD, and MYSQL_DATABASE environment variables required"}',
                file=sys.stderr,
            )
            sys.exit(1)

    def _connect(self):
        """Create a database connection."""
        return mysql.connector.connect(
            host=self.host,
            user=self.user,
            password=self.password,
            database=self.database,
            port=self.port,
            connection_timeout=30,
        )

    def query(self, sql):
        """Execute a SQL query and return results."""
        conn = None
        try:
            conn = self._connect()
            cursor = conn.cursor(dictionary=True)
            cursor.execute(sql)
            if cursor.description:
                rows = cursor.fetchall()
                columns = [desc[0] for desc in cursor.description]
                return {
                    "columns": columns,
                    "rows": rows,
                    "row_count": len(rows),
                }
            else:
                conn.commit()
                return {"success": True, "rows_affected": cursor.rowcount}
        except MySQLError as e:
            return {"error": str(e)}
        finally:
            if conn and conn.is_connected():
                conn.close()

    def list_tables(self):
        """List all tables in the current database."""
        return self.query("SHOW TABLES")

    def describe_table(self, table):
        """Describe a table's columns."""
        try:
            conn = self._connect()
            cursor = conn.cursor(dictionary=True)
            cursor.execute(f"DESCRIBE `{table}`")
            rows = cursor.fetchall()
            return {
                "table": table,
                "columns": rows,
                "column_count": len(rows),
            }
        except MySQLError as e:
            return {"error": str(e)}
        finally:
            if conn and conn.is_connected():
                conn.close()

    def list_databases(self):
        """List all databases."""
        return self.query("SHOW DATABASES")


def main():
    parser = argparse.ArgumentParser(description="MySQL CLI")
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")

    query_parser = subparsers.add_parser("query", help="Execute a SQL query")
    query_parser.add_argument("--sql", required=True, help="SQL query to execute")

    subparsers.add_parser("list-tables", help="List all tables")

    desc_parser = subparsers.add_parser("describe-table", help="Describe a table")
    desc_parser.add_argument("--table", required=True, help="Table name")

    subparsers.add_parser("list-databases", help="List all databases")

    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    client = MySQLClient()

    if args.command == "query":
        result = client.query(args.sql)
    elif args.command == "list-tables":
        result = client.list_tables()
    elif args.command == "describe-table":
        result = client.describe_table(args.table)
    elif args.command == "list-databases":
        result = client.list_databases()

    print(json.dumps(result, indent=2, default=str))

    if "error" in result:
        sys.exit(1)
    sys.exit(0)


if __name__ == "__main__":
    main()

