"""PagerDuty CLI for managing incidents."""
import argparse
import json
import os
import sys
import requests


class PagerDutyClient:
    """Client for PagerDuty REST API interactions."""

    def __init__(self):
        self.api_key = os.environ.get("PAGERDUTY_API_KEY", "")
        if not self.api_key:
            print(
                '{"error": "PAGERDUTY_API_KEY environment variable required"}',
                file=sys.stderr,
            )
            sys.exit(1)
        self.base_url = "https://api.pagerduty.com"
        self.headers = {
            "Authorization": f"Token token={self.api_key}",
            "Content-Type": "application/json",
            "Accept": "application/vnd.pagerduty+json;version=2",
        }

    def list_incidents(self, status=None):
        """List incidents, optionally filtered by status."""
        params = {"limit": 100, "sort_by": "created_at:desc"}
        if status:
            params["statuses[]"] = status

        try:
            response = requests.get(
                f"{self.base_url}/incidents",
                headers=self.headers,
                params=params,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def create_incident(self, service_id, title):
        """Create a new incident."""
        payload = {
            "incident": {
                "type": "incident",
                "title": title,
                "service": {
                    "id": service_id,
                    "type": "service_reference",
                },
            }
        }

        try:
            response = requests.post(
                f"{self.base_url}/incidents",
                headers=self.headers,
                json=payload,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def acknowledge(self, incident_id):
        """Acknowledge an incident."""
        payload = {
            "incident": {
                "type": "incident_reference",
                "status": "acknowledged",
            }
        }

        try:
            response = requests.put(
                f"{self.base_url}/incidents/{incident_id}",
                headers=self.headers,
                json=payload,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def resolve(self, incident_id):
        """Resolve an incident."""
        payload = {
            "incident": {
                "type": "incident_reference",
                "status": "resolved",
            }
        }

        try:
            response = requests.put(
                f"{self.base_url}/incidents/{incident_id}",
                headers=self.headers,
                json=payload,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }


def main():
