#!/usr/bin/env python3
"""Pinecone CLI for managing vector database indexes and vectors."""
import argparse
import json
import os
import sys

from pinecone import Pinecone


class PineconeClient:
    """Client for Pinecone API interactions."""

    def __init__(self):
        self.api_key = os.environ.get("PINECONE_API_KEY", "")
        if not self.api_key:
            print(
                '{"error": "PINECONE_API_KEY environment variable required"}',
                file=sys.stderr,
            )
            sys.exit(1)
        self.pc = Pinecone(api_key=self.api_key)

    def list_indexes(self):
        """List all indexes."""
        try:
            indexes = self.pc.list_indexes()
            return {
                "indexes": [
                    {
                        "name": idx.name,
                        "dimension": idx.dimension,
                        "metric": idx.metric,
                        "host": idx.host,
                        "status": {"ready": idx.status.ready},
                    }
                    for idx in indexes
                ]
            }
        except Exception as e:
            return {"error": str(e)}

    def describe_index(self, index_name):
        """Describe an index."""
        try:
            desc = self.pc.describe_index(index_name)
            return {
                "name": desc.name,
                "dimension": desc.dimension,
                "metric": desc.metric,
                "host": desc.host,
                "status": {"ready": desc.status.ready},
            }
        except Exception as e:
            return {"error": str(e)}

    def query(self, index_name, vector, top_k=10):
        """Query an index with a vector."""
        try:
            index = self.pc.Index(index_name)
            results = index.query(vector=vector, top_k=top_k, include_metadata=True)
            return {
                "matches": [
                    {
                        "id": m.id,
                        "score": m.score,
                        "metadata": m.metadata,
                    }
                    for m in results.matches
                ]
            }
        except Exception as e:
            return {"error": str(e)}

    def upsert(self, index_name, vectors):
        """Upsert vectors into an index."""
        try:
            index = self.pc.Index(index_name)
            result = index.upsert(vectors=vectors)
            return {"upserted_count": result.upserted_count}
        except Exception as e:
            return {"error": str(e)}

    def delete(self, index_name, ids):
        """Delete vectors by IDs."""
        try:
            index = self.pc.Index(index_name)
            index.delete(ids=ids)
            return {"success": True, "deleted_ids": ids}
        except Exception as e:
            return {"error": str(e)}


def main():
    parser = argparse.ArgumentParser(description="Pinecone CLI")
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")

    subparsers.add_parser("list-indexes", help="List all indexes")

    describe_parser = subparsers.add_parser("describe-index", help="Describe an index")
    describe_parser.add_argument("--index", required=True, help="Index name")

    query_parser = subparsers.add_parser("query", help="Query an index")
    query_parser.add_argument("--index", required=True, help="Index name")
    query_parser.add_argument(
        "--vector-json", required=True, help="JSON array of floats for the query vector"
    )
    query_parser.add_argument(
        "--top-k", type=int, default=10, help="Number of results to return"
    )

    upsert_parser = subparsers.add_parser("upsert", help="Upsert vectors")
    upsert_parser.add_argument("--index", required=True, help="Index name")
    upsert_parser.add_argument(
        "--vectors-json",
        required=True,
        help='JSON array of vectors (e.g., \'[{"id":"v1","values":[0.1,0.2]}]\')',
    )

    delete_parser = subparsers.add_parser("delete", help="Delete vectors by IDs")
    delete_parser.add_argument("--index", required=True, help="Index name")
    delete_parser.add_argument(
        "--ids-json", required=True, help='JSON array of IDs (e.g., \'["v1","v2"]\')'
    )

    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    client = PineconeClient()

    if args.command == "list-indexes":
        result = client.list_indexes()
    elif args.command == "describe-index":
        result = client.describe_index(args.index)
    elif args.command == "query":
        vector = json.loads(args.vector_json)
        result = client.query(args.index, vector, args.top_k)
    elif args.command == "upsert":
        vectors = json.loads(args.vectors_json)
        result = client.upsert(args.index, vectors)
    elif args.command == "delete":
        ids = json.loads(args.ids_json)
        result = client.delete(args.index, ids)

    print(json.dumps(result, indent=2))

    if "error" in result:
        sys.exit(1)
    sys.exit(0)


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""PostgreSQL CLI for querying and managing PostgreSQL databases."""
import argparse
import json
import os
import sys

try:
    import psycopg2
    import psycopg2.extras
except ImportError:
    print(
        '{"error": "psycopg2-binary package required. Install with: pip install psycopg2-binary>=2.9.0"}',
        file=sys.stderr,
    )
    sys.exit(1)


class PostgreSQLClient:
    """Client for PostgreSQL interactions."""

    def __init__(self):
        self.postgres_url = os.environ.get("POSTGRES_URL", "")
        if not self.postgres_url:
            print(
                '{"error": "POSTGRES_URL environment variable required"}',
                file=sys.stderr,
            )
            sys.exit(1)

    def _connect(self):
        """Create a database connection."""
        try:
            return psycopg2.connect(self.postgres_url)
        except psycopg2.Error as e:
            return None, {"error": f"Connection failed: {str(e)}"}

    def query(self, sql):
        """Execute a SQL query and return results."""
        try:
            conn = psycopg2.connect(self.postgres_url)
            cursor = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
            cursor.execute(sql)
            if cursor.description:
                rows = cursor.fetchall()
                columns = [desc[0] for desc in cursor.description]
                return {
                    "columns": columns,
                    "rows": [dict(row) for row in rows],
                    "row_count": len(rows),
                }
            else:
                conn.commit()
                return {"success": True, "rows_affected": cursor.rowcount}
        except psycopg2.Error as e:
            return {"error": str(e)}
        finally:
            if "conn" in locals():
                conn.close()

    def list_tables(self):
        """List all tables in the current database."""
        sql = """
            SELECT table_schema, table_name, table_type
            FROM information_schema.tables
            WHERE table_schema NOT IN ('pg_catalog', 'information_schema')
            ORDER BY table_schema, table_name
        """
        return self.query(sql)

    def describe_table(self, table):
        """Describe a table's columns."""
        sql = """
            SELECT column_name, data_type, is_nullable, column_default
            FROM information_schema.columns
            WHERE table_name = %s
            ORDER BY ordinal_position
        """
        try:
            conn = psycopg2.connect(self.postgres_url)
            cursor = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
            cursor.execute(sql, (table,))
            rows = cursor.fetchall()
            return {
                "table": table,
                "columns": [dict(row) for row in rows],
                "column_count": len(rows),
            }
        except psycopg2.Error as e:
            return {"error": str(e)}
        finally:
            if "conn" in locals():
                conn.close()

    def list_databases(self):
        """List all databases."""
        sql = "SELECT datname, pg_database_size(datname) as size_bytes FROM pg_database WHERE datistemplate = false ORDER BY datname"
        return self.query(sql)


def main():
    parser = argparse.ArgumentParser(description="PostgreSQL CLI")
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")

    query_parser = subparsers.add_parser("query", help="Execute a SQL query")
    query_parser.add_argument("--sql", required=True, help="SQL query to execute")

    subparsers.add_parser("list-tables", help="List all tables")

    desc_parser = subparsers.add_parser("describe-table", help="Describe a table")
    desc_parser.add_argument("--table", required=True, help="Table name")

    subparsers.add_parser("list-databases", help="List all databases")

    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    client = PostgreSQLClient()

    if args.command == "query":
        result = client.query(args.sql)
    elif args.command == "list-tables":
        result = client.list_tables()
    elif args.command == "describe-table":
        result = client.describe_table(args.table)
    elif args.command == "list-databases":
        result = client.list_databases()

    print(json.dumps(result, indent=2, default=str))

    if "error" in result:
        sys.exit(1)
    sys.exit(0)


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""PostHog CLI for capturing events, running queries, and listing feature flags."""
import argparse
import json
import os
import sys
import requests


class PostHogClient:
    """Client for PostHog API interactions."""

    def __init__(self):
        self.api_key = os.environ.get("POSTHOG_API_KEY", "")
        if not self.api_key:
            print(
                '{"error": "POSTHOG_API_KEY environment variable required"}',
                file=sys.stderr,
            )
            sys.exit(1)
        self.host = os.environ.get("POSTHOG_HOST", "https://app.posthog.com").rstrip("/")
        self.headers = {
            "Authorization": f"Bearer {self.api_key}",
            "Content-Type": "application/json",
        }

    def _get_project_id(self):
        """Get the first project ID for the current user."""
        try:
            response = requests.get(
                f"{self.host}/api/projects/",
                headers=self.headers,
                timeout=30,
            )
            response.raise_for_status()
            data = response.json()
            results = data.get("results", data) if isinstance(data, dict) else data
            if results:
                return results[0].get("id")
            return None
        except requests.exceptions.RequestException:
            return None

    def capture(self, event, distinct_id, properties_json=None):
        """Capture an event."""
        payload = {
            "event": event,
            "distinct_id": distinct_id,
            "properties": {},
        }
        if properties_json:
            try:
                payload["properties"] = json.loads(properties_json)
            except json.JSONDecodeError as e:
                return {"error": f"Invalid properties JSON: {e}"}

        try:
            response = requests.post(
                f"{self.host}/capture/",
                headers={"Content-Type": "application/json"},
                json={
                    "api_key": self.api_key,
                    "event": event,
                    "distinct_id": distinct_id,
                    "properties": payload["properties"],
                },
                timeout=30,
            )
            response.raise_for_status()
            return {"success": True, "status_code": response.status_code}
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def query(self, query_json):
        """Run a HogQL or insights query."""
        try:
            query_obj = json.loads(query_json)
        except json.JSONDecodeError as e:
            return {"error": f"Invalid query JSON: {e}"}

        project_id = self._get_project_id()
        if not project_id:
            return {"error": "Could not determine project ID"}

        try:
            response = requests.post(
                f"{self.host}/api/projects/{project_id}/query/",
                headers=self.headers,
                json={"query": query_obj},
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def list_feature_flags(self):
        """List all feature flags."""
        project_id = self._get_project_id()
        if not project_id:
            return {"error": "Could not determine project ID"}

        try:
            response = requests.get(
                f"{self.host}/api/projects/{project_id}/feature_flags/",
                headers=self.headers,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }


def main():
    parser = argparse.ArgumentParser(description="PostHog CLI")
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")

    capture_parser = subparsers.add_parser("capture", help="Capture an event")
    capture_parser.add_argument("--event", required=True, help="Event name")
    capture_parser.add_argument(
        "--distinct-id", required=True, help="Distinct user ID"
    )
    capture_parser.add_argument(
        "--properties-json", help="JSON string of event properties"
    )

    query_parser = subparsers.add_parser("query", help="Run a query")
    query_parser.add_argument(
        "--query-json", required=True,
        help='JSON query object (e.g., \'{"kind":"HogQLQuery","query":"SELECT ..."}\')',
    )

    subparsers.add_parser("list-feature-flags", help="List feature flags")

    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    client = PostHogClient()

    if args.command == "capture":
        result = client.capture(
            args.event, args.distinct_id,
            properties_json=getattr(args, "properties_json", None),
        )
    elif args.command == "query":
        result = client.query(args.query_json)
    elif args.command == "list-feature-flags":
        result = client.list_feature_flags()

    print(json.dumps(result, indent=2))

    if isinstance(result, dict) and "error" in result:
        sys.exit(1)
    sys.exit(0)


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""PyPI CLI for searching packages, listing versions, and getting release data."""
import argparse
import json
import sys
import requests


class PyPIClient:
    """Client for PyPI API interactions."""

    def __init__(self):
        self.base_url = "https://pypi.org"
        self.headers = {
            "Accept": "application/json",
        }

    def get_package(self, name):
        """Get package metadata."""
        try:
            response = requests.get(
                f"{self.base_url}/pypi/{name}/json",
                headers=self.headers,
                timeout=30,
            )
            response.raise_for_status()
            data = response.json()
            info = data.get("info", {})
            return {
                "name": info.get("name"),
                "version": info.get("version"),
                "summary": info.get("summary"),
                "description": info.get("description"),
                "author": info.get("author"),
                "author_email": info.get("author_email"),
                "license": info.get("license"),
                "home_page": info.get("home_page"),
                "project_url": info.get("project_url"),
                "requires_python": info.get("requires_python"),
                "keywords": info.get("keywords"),
            }
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def search(self, query):
        """Search for packages using the PyPI simple API and XMLRPC fallback."""
        try:
            response = requests.get(
                f"https://pypi.org/search/",
                headers={"Accept": "application/json"},
                params={"q": query},
                timeout=30,
            )
            # PyPI search page returns HTML, so we use a workaround
            # by searching via the warehouse API
            response = requests.get(
                f"https://pypi.org/pypi/{query}/json",
                headers=self.headers,
                timeout=30,
            )
            if response.status_code == 200:
                data = response.json()
                info = data.get("info", {})
                return {
                    "results": [
                        {
                            "name": info.get("name"),
                            "version": info.get("version"),
                            "summary": info.get("summary"),
                        }
                    ]
                }
            # If exact match not found, return helpful message
            return {
                "results": [],
                "note": f"No exact match for '{query}'. Try get-package with the exact name.",
            }
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def list_versions(self, name):
        """List all versions of a package."""
        try:
            response = requests.get(
                f"{self.base_url}/pypi/{name}/json",
                headers=self.headers,
                timeout=30,
            )
            response.raise_for_status()
            data = response.json()
            versions = list(data.get("releases", {}).keys())
            return {
                "name": name,
                "versions": versions,
                "total": len(versions),
            }
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def get_release(self, name, version):
        """Get release data for a specific version."""
        try:
            response = requests.get(
                f"{self.base_url}/pypi/{name}/{version}/json",
                headers=self.headers,
                timeout=30,
            )
            response.raise_for_status()
            data = response.json()
            info = data.get("info", {})
            urls = data.get("urls", [])
            return {
                "name": info.get("name"),
                "version": info.get("version"),
                "summary": info.get("summary"),
                "requires_python": info.get("requires_python"),
                "requires_dist": info.get("requires_dist"),
                "files": [
                    {
                        "filename": u.get("filename"),
                        "packagetype": u.get("packagetype"),
                        "size": u.get("size"),
                        "upload_time": u.get("upload_time"),
                    }
                    for u in urls
                ],
            }
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }


def main():
    parser = argparse.ArgumentParser(description="PyPI CLI")
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")

    get_parser = subparsers.add_parser("get-package", help="Get package metadata")
    get_parser.add_argument("--name", required=True, help="Package name")

    search_parser = subparsers.add_parser("search", help="Search for packages")
    search_parser.add_argument("--query", required=True, help="Search query")

    versions_parser = subparsers.add_parser(
        "list-versions", help="List package versions"
    )
    versions_parser.add_argument("--name", required=True, help="Package name")

    release_parser = subparsers.add_parser(
        "get-release", help="Get release data for a specific version"
    )
    release_parser.add_argument("--name", required=True, help="Package name")
    release_parser.add_argument("--version", required=True, help="Version string")

    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    client = PyPIClient()

    if args.command == "get-package":
        result = client.get_package(args.name)
    elif args.command == "search":
        result = client.search(args.query)
    elif args.command == "list-versions":
        result = client.list_versions(args.name)
    elif args.command == "get-release":
        result = client.get_release(args.name, args.version)

    print(json.dumps(result, indent=2))

    if isinstance(result, dict) and "error" in result:
        sys.exit(1)
    sys.exit(0)


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""Railway CLI for managing projects, services, and deployments."""
import argparse
import json
import os
import sys
import requests


class RailwayClient:
    """Client for Railway GraphQL API interactions."""

    def __init__(self):
        self.token = os.environ.get("RAILWAY_TOKEN", "")
        if not self.token:
            print(
                '{"error": "RAILWAY_TOKEN environment variable required"}',
                file=sys.stderr,
            )
            sys.exit(1)
        self.base_url = "https://backboard.railway.app/graphql/v2"
        self.headers = {
            "Authorization": f"Bearer {self.token}",
            "Content-Type": "application/json",
        }

    def _graphql(self, query, variables=None):
        """Execute a GraphQL query."""
        payload = {"query": query}
        if variables:
            payload["variables"] = variables
        try:
            response = requests.post(
                self.base_url,
                headers=self.headers,
                json=payload,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def list_projects(self):
        """List all projects."""
        query = """
        query {
          projects {
            edges {
              node {
                id
                name
                description
                createdAt
                updatedAt
              }
            }
          }
        }
        """
        return self._graphql(query)

    def get_project(self, project_id):
        """Get project details."""
        query = """
        query ($projectId: String!) {
          project(id: $projectId) {
            id
            name
            description
            createdAt
            updatedAt
            environments {
              edges {
                node {
                  id
                  name
                }
              }
            }
          }
        }
        """
        return self._graphql(query, {"projectId": project_id})

    def list_services(self, project_id):
        """List services in a project."""
        query = """
        query ($projectId: String!) {
          project(id: $projectId) {
            services {
              edges {
                node {
                  id
                  name
                  createdAt
                  updatedAt
                }
              }
            }
          }
        }
        """
        return self._graphql(query, {"projectId": project_id})

    def list_deployments(self, project_id):
        """List deployments for a project."""
        query = """
        query ($projectId: String!) {
          deployments(input: { projectId: $projectId }, first: 20) {
            edges {
              node {
                id
                status
                createdAt
                updatedAt
              }
            }
          }
        }
        """
        return self._graphql(query, {"projectId": project_id})

    def get_deployment(self, deployment_id):
        """Get deployment details."""
        query = """
        query ($deploymentId: String!) {
          deployment(id: $deploymentId) {
            id
            status
            createdAt
            updatedAt
            staticUrl
          }
        }
        """
        return self._graphql(query, {"deploymentId": deployment_id})


def main():
    parser = argparse.ArgumentParser(description="Railway CLI")
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")

    subparsers.add_parser("list-projects", help="List all projects")

    project_parser = subparsers.add_parser("get-project", help="Get project details")
    project_parser.add_argument("--project-id", required=True, help="Project ID")

    services_parser = subparsers.add_parser(
        "list-services", help="List services in a project"
    )
    services_parser.add_argument("--project-id", required=True, help="Project ID")

    deploys_parser = subparsers.add_parser(
        "list-deployments", help="List deployments"
    )
    deploys_parser.add_argument("--project-id", required=True, help="Project ID")

    deploy_parser = subparsers.add_parser(
        "get-deployment", help="Get deployment details"
    )
    deploy_parser.add_argument("--deployment-id", required=True, help="Deployment ID")

    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    client = RailwayClient()

    if args.command == "list-projects":
        result = client.list_projects()
    elif args.command == "get-project":
        result = client.get_project(args.project_id)
    elif args.command == "list-services":
        result = client.list_services(args.project_id)
    elif args.command == "list-deployments":
        result = client.list_deployments(args.project_id)
    elif args.command == "get-deployment":
        result = client.get_deployment(args.deployment_id)

    print(json.dumps(result, indent=2))

    if isinstance(result, dict) and "error" in result:
        sys.exit(1)
    sys.exit(0)


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""Redis CLI for interacting with Redis key-value store."""
import argparse
import json
import os
import sys

try:
    import redis
except ImportError:
    print(
        '{"error": "redis package required. Install with: pip install redis>=5.0.0"}',
        file=sys.stderr,
    )
    sys.exit(1)


class RedisClient:
    """Client for Redis interactions."""

    def __init__(self):
        self.redis_url = os.environ.get("REDIS_URL", "")
        if not self.redis_url:
            print(
                '{"error": "REDIS_URL environment variable required"}',
                file=sys.stderr,
            )
            sys.exit(1)
        try:
            self.client = redis.from_url(self.redis_url, decode_responses=True)
        except Exception as e:
            print(
                json.dumps({"error": f"Failed to connect to Redis: {str(e)}"}),
                file=sys.stderr,
            )
            sys.exit(1)

    def get(self, key):
        """Get value by key."""
        try:
            value = self.client.get(key)
            if value is None:
                return {"key": key, "value": None, "exists": False}
            return {"key": key, "value": value, "exists": True}
        except redis.RedisError as e:
            return {"error": str(e)}

    def set(self, key, value, ttl=None):
        """Set a key-value pair with optional TTL."""
        try:
            if ttl:
                self.client.setex(key, int(ttl), value)
            else:
                self.client.set(key, value)
            return {"success": True, "key": key, "ttl": ttl}
        except redis.RedisError as e:
            return {"error": str(e)}

    def delete(self, key):
        """Delete a key."""
        try:
            deleted = self.client.delete(key)
            return {"success": True, "key": key, "deleted": deleted}
        except redis.RedisError as e:
            return {"error": str(e)}

    def keys(self, pattern="*"):
        """List keys matching a pattern."""
        try:
            matched_keys = self.client.keys(pattern)
            return {"pattern": pattern, "keys": matched_keys, "count": len(matched_keys)}
        except redis.RedisError as e:
            return {"error": str(e)}

    def info(self):
        """Get Redis server info."""
        try:
            server_info = self.client.info()
            return {"info": server_info}
        except redis.RedisError as e:
            return {"error": str(e)}


def main():
    parser = argparse.ArgumentParser(description="Redis CLI")
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")

    get_parser = subparsers.add_parser("get", help="Get value by key")
    get_parser.add_argument("--key", required=True, help="Redis key")

    set_parser = subparsers.add_parser("set", help="Set a key-value pair")
    set_parser.add_argument("--key", required=True, help="Redis key")
