#!/usr/bin/env python3
"""Upstash CLI for interacting with Upstash Redis via the REST API."""
import argparse
import json
import os
import sys
import requests


class UpstashClient:
    """Client for Upstash Redis REST API interactions."""

    def __init__(self):
        self.url = os.environ.get("UPSTASH_REDIS_REST_URL", "").rstrip("/")
        if not self.url:
            print(
                '{"error": "UPSTASH_REDIS_REST_URL environment variable required"}',
                file=sys.stderr,
            )
            sys.exit(1)
        self.token = os.environ.get("UPSTASH_REDIS_REST_TOKEN", "")
        if not self.token:
            print(
                '{"error": "UPSTASH_REDIS_REST_TOKEN environment variable required"}',
                file=sys.stderr,
            )
            sys.exit(1)
        self.headers = {
            "Authorization": f"Bearer {self.token}",
            "Content-Type": "application/json",
        }

    def _execute(self, command):
        """Execute a Redis command via Upstash REST API."""
        try:
            response = requests.post(
                self.url,
                headers=self.headers,
                json=command,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def get(self, key):
        """Get the value of a key."""
        return self._execute(["GET", key])

    def set(self, key, value, ex=None):
        """Set a key-value pair with optional expiry."""
        command = ["SET", key, value]
        if ex is not None:
            command.extend(["EX", str(ex)])
        return self._execute(command)

    def delete(self, key):
        """Delete a key."""
        return self._execute(["DEL", key])

    def keys(self, pattern="*"):
        """List keys matching a pattern."""
        return self._execute(["KEYS", pattern])

    def incr(self, key):
        """Increment a key's integer value."""
        return self._execute(["INCR", key])


def main():
    parser = argparse.ArgumentParser(description="Upstash CLI")
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")

    get_parser = subparsers.add_parser("get", help="Get a key's value")
    get_parser.add_argument("--key", required=True, help="Key name")

    set_parser = subparsers.add_parser("set", help="Set a key-value pair")
    set_parser.add_argument("--key", required=True, help="Key name")
    set_parser.add_argument("--value", required=True, help="Value to set")
    set_parser.add_argument(
        "--ex", type=int, help="Expiry time in seconds"
    )

    del_parser = subparsers.add_parser("del", help="Delete a key")
    del_parser.add_argument("--key", required=True, help="Key name")

    keys_parser = subparsers.add_parser("keys", help="List keys matching a pattern")
    keys_parser.add_argument(
        "--pattern", default="*", help="Glob pattern (default: *)"
    )

    incr_parser = subparsers.add_parser("incr", help="Increment a key")
    incr_parser.add_argument("--key", required=True, help="Key name")

    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    client = UpstashClient()

    if args.command == "get":
        result = client.get(args.key)
    elif args.command == "set":
        result = client.set(args.key, args.value, ex=getattr(args, "ex", None))
    elif args.command == "del":
        result = client.delete(args.key)
    elif args.command == "keys":
        result = client.keys(args.pattern)
    elif args.command == "incr":
        result = client.incr(args.key)

    print(json.dumps(result, indent=2))

    if isinstance(result, dict) and "error" in result:
        sys.exit(1)
    sys.exit(0)


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""HashiCorp Vault CLI for reading, writing, listing, and deleting secrets."""
import argparse
import json
import os
import sys
import requests


class VaultClient:
    """Client for HashiCorp Vault API interactions."""

    def __init__(self):
        self.vault_addr = os.environ.get("VAULT_ADDR", "").rstrip("/")
        if not self.vault_addr:
            print(
                '{"error": "VAULT_ADDR environment variable required"}',
                file=sys.stderr,
            )
            sys.exit(1)
        self.vault_token = os.environ.get("VAULT_TOKEN", "")
        if not self.vault_token:
            print(
                '{"error": "VAULT_TOKEN environment variable required"}',
                file=sys.stderr,
            )
            sys.exit(1)
        self.base_url = f"{self.vault_addr}/v1"
        self.headers = {
            "X-Vault-Token": self.vault_token,
            "Content-Type": "application/json",
        }

    def read(self, path):
        """Read a secret at the given path."""
        try:
            response = requests.get(
                f"{self.base_url}/{path}",
                headers=self.headers,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def write(self, path, data):
        """Write a secret at the given path."""
        try:
            response = requests.post(
                f"{self.base_url}/{path}",
                headers=self.headers,
                json=data,
                timeout=30,
            )
            response.raise_for_status()
            if response.text:
                return response.json()
            return {"success": True, "path": path}
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def list_secrets(self, path):
        """List secrets at the given path."""
        try:
            response = requests.request(
                "LIST",
                f"{self.base_url}/{path}",
                headers=self.headers,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def delete(self, path):
        """Delete a secret at the given path."""
        try:
            response = requests.delete(
                f"{self.base_url}/{path}",
                headers=self.headers,
                timeout=30,
            )
            response.raise_for_status()
            return {"success": True, "path": path}
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }


def main():
    parser = argparse.ArgumentParser(description="HashiCorp Vault CLI")
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")

    read_parser = subparsers.add_parser("read", help="Read a secret")
    read_parser.add_argument("--path", required=True, help="Secret path")

    write_parser = subparsers.add_parser("write", help="Write a secret")
    write_parser.add_argument("--path", required=True, help="Secret path")
    write_parser.add_argument(
        "--data-json", required=True, help="JSON object of data to write"
    )

    list_parser = subparsers.add_parser("list", help="List secrets")
    list_parser.add_argument("--path", required=True, help="Secret path")

    delete_parser = subparsers.add_parser("delete", help="Delete a secret")
    delete_parser.add_argument("--path", required=True, help="Secret path")

    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    client = VaultClient()

    if args.command == "read":
        result = client.read(args.path)
    elif args.command == "write":
        data = json.loads(args.data_json)
        result = client.write(args.path, data)
    elif args.command == "list":
        result = client.list_secrets(args.path)
    elif args.command == "delete":
        result = client.delete(args.path)

    print(json.dumps(result, indent=2))

    if "error" in result:
        sys.exit(1)
    sys.exit(0)


if __name__ == "__main__":
    main()

